import io
import logging
import socket
from typing import Iterator

logger = logging.getLogger(__name__)


class SocketFileIterator:
    """A class that encapsulates a TCP server that yields file objects."""

    def __init__(self, host: str = "0.0.0.0", port: int = 5942) -> None:
        self.host = host
        self.port = port

    def __iter__(self) -> Iterator[io.BufferedRWPair]:
        """Wait for a client to connect, and yields a file object that can be used
        to read and write from to communicate with the client. Can be stopped with
        KeyBoardInterrupt.
        """
        with socket.socket(socket.AF_INET, socket.SOCK_STREAM) as server_socket:
            server_socket.bind((self.host, self.port))
            server_socket.listen(1)
            # On Windows, the Ctrl+C does not interrupt `.accept()`.
            # A way to fix that is to stop waiting periodically:
            server_socket.settimeout(0.5)
            logger.info(f"Server listening on {self.host}:{self.port}")
            while True:
                try:
                    conn, addr = server_socket.accept()
                except socket.timeout:
                    continue
                with conn:
                    logger.info(f"Connected by {addr}")
                    with conn.makefile("rwb") as file:
                        yield file
                logger.info(f"{addr}: Disconnected")
